import{_ as e,o as t,c as o,a0 as r}from"./chunks/framework.CWk8AOcY.js";const b=JSON.parse('{"title":"更新日志","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"zh/changelog.md"}'),n={name:"changelog.md"};function l(i,a,s,h,d,u){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="更新日志" tabindex="-1">更新日志 <a class="header-anchor" href="#更新日志" aria-label="Permalink to &quot;更新日志&quot;">​</a></h1><h2 id="_2026-04-27-发布-v0-1-2" tabindex="-1">2026.04.27 发布 v0.1.2 <a class="header-anchor" href="#_2026-04-27-发布-v0-1-2" aria-label="Permalink to &quot;2026.04.27 发布 v0.1.2&quot;">​</a></h2><h3 id="🛠️-关键修复" tabindex="-1">🛠️ 关键修复 <a class="header-anchor" href="#🛠️-关键修复" aria-label="Permalink to &quot;🛠️ 关键修复&quot;">​</a></h3><ul><li><strong>修复</strong>了当沙箱模板不存在时，CubeMaster 返回 5xx 而非 4xx 的问题。</li><li><strong>修复</strong>了 v0.1.1 一键部署过程中 SSL RootCA 证书缺失的问题。</li><li><strong>修复</strong>了 v0.1.1 部署过程中 CubeProxy 镜像构建失败的问题。</li></ul><h2 id="_2026-04-24-发布-v0-1-1" tabindex="-1">2026.04.24 发布 v0.1.1 <a class="header-anchor" href="#_2026-04-24-发布-v0-1-1" aria-label="Permalink to &quot;2026.04.24 发布 v0.1.1&quot;">​</a></h2><h3 id="🛠️-关键修复-1" tabindex="-1">🛠️ 关键修复 <a class="header-anchor" href="#🛠️-关键修复-1" aria-label="Permalink to &quot;🛠️ 关键修复&quot;">​</a></h3><ul><li><strong>修复</strong>了模板重建时未使用最新 vmlinux 的问题，提升了沙箱环境稳定性。</li><li><strong>更新</strong>了一键安装脚本，支持非 eth0 网卡，解决了 CubeProxy CA 证书稳定性问题。</li><li><strong>禁用</strong>了初始化阶段主网卡上的 GRO，以提升网络稳定性。</li><li><strong>修复</strong>了模板清理时目标不存在场景下的错误处理，确保返回正确错误。</li></ul><h3 id="✨-新功能" tabindex="-1">✨ 新功能 <a class="header-anchor" href="#✨-新功能" aria-label="Permalink to &quot;✨ 新功能&quot;">​</a></h3><ul><li><strong>新增</strong> <code>cubebox destroy</code> 命令，支持通过 CLI 删除沙箱。</li><li><strong>新增</strong> OpenAI Agents SDK（含 Code Interpreter）集成示例。</li></ul><h3 id="📚-文档更新" tabindex="-1">📚 文档更新 <a class="header-anchor" href="#📚-文档更新" aria-label="Permalink to &quot;📚 文档更新&quot;">​</a></h3><ul><li><strong>重写</strong>了 HTTPS 与域名配置文档，补充了泛域名 DNS 记录说明。</li></ul><h3 id="⚙️-工程改进" tabindex="-1">⚙️ 工程改进 <a class="header-anchor" href="#⚙️-工程改进" aria-label="Permalink to &quot;⚙️ 工程改进&quot;">​</a></h3><ul><li><strong>实现</strong>了多组件并行 CI 构建流水线，优化构建效率。</li><li><strong>新增</strong>了将 GitHub Release 资产自动同步到 <code>cnb.cool/CubeSandbox/CubeSandbox</code> 的能力。</li></ul><h2 id="_2026-04-20-发布-v0-1-0" tabindex="-1">2026.04.20 发布 v0.1.0 <a class="header-anchor" href="#_2026-04-20-发布-v0-1-0" aria-label="Permalink to &quot;2026.04.20 发布 v0.1.0&quot;">​</a></h2><h3 id="cube-sandbox-首次开源发布" tabindex="-1">Cube Sandbox 首次开源发布 <a class="header-anchor" href="#cube-sandbox-首次开源发布" aria-label="Permalink to &quot;Cube Sandbox 首次开源发布&quot;">​</a></h3><p><strong>面向 AI Agent 的极速、高并发、安全且轻量化沙箱。</strong></p><h3 id="核心亮点" tabindex="-1">核心亮点 <a class="header-anchor" href="#核心亮点" aria-label="Permalink to &quot;核心亮点&quot;">​</a></h3><p>Cube Sandbox 是一款基于 RustVMM 与 KVM 构建的高性能、开箱即用的安全沙箱服务。它既支持单机部署，也可以轻松扩展到多机集群。Cube Sandbox 对外兼容 E2B SDK，能够在 60ms 内创建具备完整服务能力的硬件隔离沙箱环境，同时将单实例内存开销控制在 5MB 以下。</p><ul><li><strong>极致冷启动：</strong> 基于资源池化预置与快照克隆技术，跳过耗时的初始化流程。可服务沙箱端到端冷启动平均耗时 &lt; 60ms。</li><li><strong>单机高密部署：</strong> 借助 CoW 技术实现极致内存复用，并通过 Rust 重构与深度裁剪运行时，将单实例内存开销降至 5MB 以下，单机可承载数千 Agent。</li><li><strong>真正的内核级隔离：</strong> 每个 Agent 运行在独立 Guest OS 内核中，避免容器逃逸风险，可安全执行任意大模型生成代码。</li><li><strong>零成本迁移（E2B 无缝替换）：</strong> 原生兼容 E2B SDK 接口，仅需替换一个 URL 环境变量，无需业务代码改动。</li><li><strong>网络安全：</strong> 基于 eBPF 的 CubeVS 在内核态实现严格的沙箱间网络隔离，并支持细粒度出站流量过滤策略。</li></ul><h3 id="生产可用" tabindex="-1">生产可用 <a class="header-anchor" href="#生产可用" aria-label="Permalink to &quot;生产可用&quot;">​</a></h3><p><strong>在开源之前，Cube Sandbox 已在腾讯云生产环境经历大规模验证，稳定可靠。</strong> 在它正式开源前，就已经支撑真实 AI Agent 业务负载并服务真实用户。</p><p>在真实生产部署中，单台物理机可在数分钟内拉起数以万计的沙箱实例。</p><p>我们今天开源的不是一个原型，而是一套已经通过真实规模考验的生产级基础设施。</p><h3 id="致每一位贡献者-过去、现在与未来" tabindex="-1">致每一位贡献者：过去、现在与未来 <a class="header-anchor" href="#致每一位贡献者-过去、现在与未来" aria-label="Permalink to &quot;致每一位贡献者：过去、现在与未来&quot;">​</a></h3><p>在这套代码公开之前，它就已经在完成自己的使命：毫秒级启动沙箱、在内核级隔离 Agent 负载，并在腾讯云真实生产流量下稳定运行。这一切并非偶然。</p><p>今天，我们打开这扇门。你们共同塑造的高性能 Agent 基础设施，将走向整个社区，属于每一位相信「安全、即时、轻量的代码执行应当开源且可自托管」的开发者。</p><p>致过去的贡献者：你们打下了地基。<br> 致未来的贡献者：你们将把地基发展成生态。</p><p>开源因你们而闪耀！</p>',28)])])}const c=e(n,[["render",l]]);export{b as __pageData,c as default};
